(function () {
  "use strict";

  window.getusrser = function getusrser() {
    var input = document.getElementById("initSearchBar");
    var searchTerm = input ? input.value.trim() : "";
    window.location.href = "search.html?q=" + encodeURIComponent(searchTerm);
  };

  if (window.innerWidth < 768) {
    Array.prototype.slice.call(document.querySelectorAll("[data-bss-disabled-mobile]")).forEach(function (element) {
      element.classList.remove("animated");
      element.removeAttribute("data-bss-hover-animate");
      element.removeAttribute("data-aos");
      element.removeAttribute("data-bss-parallax-bg");
      element.removeAttribute("data-bss-scroll-zoom");
    });
  }

  document.addEventListener("DOMContentLoaded", function () {
    Array.prototype.slice.call(document.querySelectorAll("[data-bss-hover-animate]")).forEach(function (element) {
      element.addEventListener("mouseenter", function (event) {
        event.target.classList.add("animated", event.target.dataset.bssHoverAnimate);
      });
      element.addEventListener("mouseleave", function (event) {
        event.target.classList.remove("animated", event.target.dataset.bssHoverAnimate);
      });
    });

    initParallax();
    initNav();
    initCopyButtons();
    initSidebarToggle();
  });

  function initParallax() {
    if (!("requestAnimationFrame" in window)) return;
    var layers = [];
    var targets = document.querySelectorAll("[data-bss-parallax-bg]");

    Array.prototype.slice.call(targets).forEach(function (target) {
      var layer = document.createElement("div");
      layer.style.backgroundImage = target.style.backgroundImage;
      layer.style.backgroundSize = "cover";
      layer.style.backgroundPosition = "center";
      layer.style.position = "absolute";
      layer.style.height = "200%";
      layer.style.width = "100%";
      layer.style.top = "0";
      layer.style.left = "0";
      layer.style.zIndex = "-100";
      target.appendChild(layer);
      target.style.position = "relative";
      target.style.background = "transparent";
      target.style.overflow = "hidden";
      layers.push(layer);
    });

    if (!layers.length) return;

    var frame;
    var visible = [];

    function collect() {
      visible = [];
      layers.forEach(function (layer) {
        var rect = layer.parentNode.getBoundingClientRect();
        if (rect.bottom > 0 && rect.top < window.innerHeight) {
          visible.push({ rect: rect, node: layer });
        }
      });
      cancelAnimationFrame(frame);
      if (visible.length) frame = requestAnimationFrame(render);
    }

    function render() {
      visible.forEach(function (entry) {
        var amount = Math.max(entry.rect.bottom, 0) / (window.innerHeight + entry.rect.height);
        entry.node.style.transform = "translate3d(0, " + -50 * amount + "%, 0)";
      });
    }

    window.addEventListener("scroll", collect);
    window.addEventListener("resize", collect);
    collect();
  }

  function initNav() {
    var nav = document.querySelector("#mainNav");
    if (!nav) return;

    var collapseElement = nav.querySelector(".navbar-collapse");
    if (collapseElement && window.bootstrap) {
      var collapse = new bootstrap.Collapse(collapseElement, { toggle: false });
      Array.prototype.slice.call(collapseElement.querySelectorAll("a")).forEach(function (link) {
        link.addEventListener("click", function () {
          collapse.hide();
        });
      });
    }

    function shrink() {
      var scrollTop = window.pageYOffset || document.documentElement.scrollTop || document.body.scrollTop || 0;
      nav.classList.toggle("navbar-shrink", scrollTop > 100);
    }

    shrink();
    document.addEventListener("scroll", shrink);
  }

  function initCopyButtons() {
    Array.prototype.slice.call(document.querySelectorAll(".copy-btn")).forEach(function (button) {
      button.addEventListener("click", function () {
        var target = document.querySelector(button.dataset.copyTarget);
        var text = target ? target.textContent.trim() : "";
        if (!text) return;
        navigator.clipboard.writeText(text).then(function () {
          var toast = document.getElementById("copyToast");
          if (toast && window.bootstrap) bootstrap.Toast.getOrCreateInstance(toast).show();
        });
      });
    });
  }

  function initSidebarToggle() {
    var toggle = document.getElementById("menu-toggle");
    var wrapper = document.getElementById("wrapper");
    if (!toggle || !wrapper) return;
    toggle.addEventListener("click", function (event) {
      event.preventDefault();
      wrapper.classList.toggle("toggled");
    });
  }
})();
